#!/usr/bin/env bash
# StreamForge v2 - IPTV Playout Manager
# Single install script — run on Proxmox host to create LXC, or inside any Debian 12 system
# Usage:  bash <(curl -fsSL https://raw.githubusercontent.com/rpoltera/streamforge/main/streamforge-install.sh)
# Update: bash <(curl -fsSL https://raw.githubusercontent.com/rpoltera/streamforge/main/streamforge-install.sh) update
# Author: rpoltera | https://github.com/rpoltera/streamforge

set -euo pipefail
export LANG=en_US.UTF-8

YW='\033[33m'; GN='\033[1;92m'; RD='\033[01;31m'; BL='\033[36m'; CL='\033[m'
BFR="\r\033[K"
CM="${GN}✔${CL}"; CROSS="${RD}✘${CL}"; TAB="  "
msg_info() { printf "${TAB}${YW}⠿${CL} %s...\n" "$1"; }
msg_ok()   { printf "${BFR}${TAB}${CM} %s\n" "$1"; }
msg_err()  { printf "${BFR}${TAB}${CROSS} %s\n" "$1"; exit 1; }

header() {
  clear 2>/dev/null || true
  echo -e "\n${YW}╔══════════════════════════════════════════╗${CL}"
  echo -e "${YW}║   StreamForge v2 - IPTV Playout Manager ║${CL}"
  echo -e "${YW}╚══════════════════════════════════════════╝${CL}\n"
}

header

# ── UPDATE MODE ───────────────────────────────────────────────────────────────
if [[ "${1:-}" == "update" ]]; then
  [[ ! -d /opt/streamforge ]] && msg_err "No StreamForge installation found"
  msg_info "Stopping StreamForge"
  systemctl stop streamforge 2>/dev/null || true
  pkill -9 -f ffmpeg 2>/dev/null || true
  msg_ok "Stopped"
  msg_info "Updating index.js"
  printf '%s' '' | base64 -d > "/opt/streamforge/server/index.js"
  msg_ok "index.js"
  msg_info "Updating package.json"
  printf '%s' '' | base64 -d > "/opt/streamforge/server/package.json"
  msg_ok "package.json"
  msg_info "Updating index.html"
  printf '%s' '' | base64 -d > "/opt/streamforge/public/index.html"
  msg_ok "index.html"
  msg_info "Updating main.css"
  printf '%s' '' | base64 -d > "/opt/streamforge/public/css/main.css"
  msg_ok "main.css"
  msg_info "Updating app.js"
  printf '%s' '' | base64 -d > "/opt/streamforge/public/js/app.js"
  msg_ok "app.js"
  msg_info "Fixing permissions"
  chown -R streamforge:streamforge /opt/streamforge
  msg_ok "Done"
  msg_info "Updating npm packages"
  su -s /bin/bash streamforge -c "cd /opt/streamforge/server && npm install --production --quiet"
  msg_ok "Done"
  msg_info "Starting StreamForge"
  systemctl start streamforge
  sleep 3
  systemctl is-active --quiet streamforge && msg_ok "StreamForge running" || msg_err "Failed to start"
  echo -e "\n${GN}Update complete!${CL}\n"
  exit 0
fi

# ── DETECT: Proxmox host or inside container ──────────────────────────────────
IS_PROXMOX=false
if command -v pct &>/dev/null 2>&1 && [[ -f /etc/pve/local/pve-ssl.pem ]]; then
  IS_PROXMOX=true
fi

if [[ "$IS_PROXMOX" == "true" ]]; then
  # ── ON PROXMOX HOST — create LXC then install inside it ───────────────────
  [[ "$EUID" -ne 0 ]] && msg_err "Run as root"

  CTID=$(pvesh get /cluster/nextid 2>/dev/null || echo "")
  [[ -z "$CTID" ]] && CTID=$(( $(pct list 2>/dev/null | awk 'END{print $1}' || echo 100) + 1 ))
  HOSTNAME="streamforge"
  MEMORY="2048"
  CORES="2"
  DISK="8"
  BRIDGE="vmbr0"
  STORAGE=$(pvesm status --content rootdir 2>/dev/null | awk 'NR==2{print $1}' || echo "local-lvm")

  echo -e "${TAB}${BL}Container ID :${CL}  $CTID"
  echo -e "${TAB}${BL}Hostname     :${CL}  $HOSTNAME"
  echo -e "${TAB}${BL}Memory       :${CL}  ${MEMORY}MB"
  echo -e "${TAB}${BL}Cores        :${CL}  $CORES vCPU"
  echo -e "${TAB}${BL}Disk         :${CL}  ${DISK}GB"
  echo -e "${TAB}${BL}Network      :${CL}  $BRIDGE (DHCP)"
  echo -e "${TAB}${BL}Storage      :${CL}  $STORAGE"
  echo -e "${TAB}${BL}OS           :${CL}  Debian 12 (unprivileged)"
  echo ""
  read -r -p "${TAB}Create container and install StreamForge? [y/N]: " yn </dev/tty
  [[ "${yn,,}" != "y" ]] && echo "Cancelled." && exit 0

  # Find or download Debian 12 template
  msg_info "Checking Debian 12 template"
  TMPL_STORE=$(pvesm status --content vztmpl 2>/dev/null | awk 'NR==2{print $1}' || echo "local")
  TMPL=$(pveam list "$TMPL_STORE" 2>/dev/null | grep "debian-12" | sort | tail -1 | awk '{print $1}')
  if [[ -z "$TMPL" ]]; then
    msg_info "Downloading Debian 12 template"
    pveam update >/dev/null 2>&1
    TMPL_NAME=$(pveam available --section system 2>/dev/null | grep "debian-12" | sort | tail -1 | awk '{print $2}')
    [[ -z "$TMPL_NAME" ]] && msg_err "Debian 12 template not found — run: pveam update"
    pveam download "$TMPL_STORE" "$TMPL_NAME" >/dev/null 2>&1
    TMPL="$TMPL_STORE:vztmpl/$TMPL_NAME"
  fi
  msg_ok "Template: $(basename "$TMPL")"

  # Create the LXC
  msg_info "Creating Debian 12 LXC (CT$CTID)"
  pct create "$CTID" "$TMPL" \
    --hostname "$HOSTNAME" \
    --memory "$MEMORY" \
    --cores "$CORES" \
    --rootfs "$STORAGE:$DISK" \
    --net0 "name=eth0,bridge=$BRIDGE,ip=dhcp" \
    --unprivileged 1 \
    --features nesting=1 \
    --onboot 1 \
    --start 0 >/dev/null 2>&1
  msg_ok "Created LXC CT$CTID"

  # Start and wait for network
  msg_info "Starting LXC"
  pct start "$CTID"
  IP=""
  for i in $(seq 1 30); do
    IP=$(pct exec "$CTID" -- hostname -I 2>/dev/null | awk '{print $1}')
    [[ -n "$IP" ]] && break
    sleep 2
  done
  [[ -z "$IP" ]] && msg_err "No IP assigned — check DHCP on bridge $BRIDGE"
  msg_ok "LXC started — IP: $IP"

  # Run install inside the LXC using the embedded inner script
  msg_info "Installing StreamForge inside CT$CTID"
  pct exec "$CTID" -- bash -c "echo '' | base64 -d | bash"
  msg_ok "Installation complete"

  # Set Proxmox container notes
  pct set "$CTID" -description "## StreamForge v2 IPTV Playout
- **Web UI:** http://$IP
- **M3U:** http://$IP/iptv.m3u
- **XMLTV:** http://$IP/xmltv.xml
- **Update:** run \`streamforge-update\` inside container

github.com/rpoltera/streamforge" 2>/dev/null || true

  echo ""
  echo -e "${GN}╔══════════════════════════════════════════════╗${CL}"
  echo -e "${GN}║   StreamForge installed successfully!        ║${CL}"
  echo -e "${GN}╠══════════════════════════════════════════════╣${CL}"
  echo -e "${GN}║                                              ║${CL}"
  echo -e "${GN}║  Container : CT$CTID ($HOSTNAME)                  ║${CL}"
  echo -e "${GN}║  Web UI    : http://$IP               ║${CL}"
  echo -e "${GN}║  M3U       : http://$IP/iptv.m3u      ║${CL}"
  echo -e "${GN}║  XMLTV     : http://$IP/xmltv.xml     ║${CL}"
  echo -e "${GN}║                                              ║${CL}"
  echo -e "${GN}║  To update: streamforge-update (in LXC)      ║${CL}"
  echo -e "${GN}╚══════════════════════════════════════════════╝${CL}"
  echo ""

else
  # ── INSIDE LXC or VM — install directly ──────────────────────────────────
  [[ "$EUID" -ne 0 ]] && msg_err "Run as root"
  echo -e "${TAB}${YW}Installing directly on this system...${CL}\n"
  echo '' | base64 -d | bash
fi
